"use client"

import Link from "next/link"

interface GameTileProps {
  code: string
  display: string
  image: string
  bgGradient: string
  overlayGradient: string
  count?: number
}

export function GameTile({
  code,
  display,
  image,
  bgGradient,
  overlayGradient,
  count,
}: GameTileProps) {
  function handleClick() {
    try {
      const secure = location.protocol === "https:" ? "; Secure" : ""
      document.cookie = `sd_game_pref=${encodeURIComponent(code)}; max-age=2592000; path=/; SameSite=Lax${secure}`
    } catch {
      // Best-effort — navigation fires regardless
    }
  }

  const ariaLabel =
    count !== undefined ? `${display} — ${count.toLocaleString()} cards` : display

  return (
    <Link
      href={`/cards?game=${encodeURIComponent(code)}`}
      aria-label={ariaLabel}
      onClick={handleClick}
      className="group relative block cursor-pointer overflow-hidden rounded-2xl transition-all duration-200 [@media(pointer:fine)]:hover:scale-[1.02] [@media(pointer:fine)]:hover:shadow-[0_8px_40px_rgba(0,0,0,0.4)] active:scale-[0.98] focus-visible:outline-2 focus-visible:outline-accent focus-visible:outline-offset-2"
      style={{ aspectRatio: "16 / 10" }}
    >
      {/* Gradient background */}
      <div
        className="absolute inset-0"
        style={{ background: bgGradient }}
      >
        {/* Pattern decoration */}
        <div
          className="absolute inset-0"
          style={{
            backgroundImage:
              "radial-gradient(circle at 30% 30%, rgba(255,255,255,0.03) 0%, transparent 60%), radial-gradient(circle at 70% 60%, rgba(255,255,255,0.02) 0%, transparent 50%)",
          }}
        />
      </div>

      {/* Card-back image background */}
      <div
        className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-40"
        style={{ backgroundImage: `url(${image})` }}
      />

      {/* Game-colour overlay */}
      <div
        className="absolute inset-0 flex flex-col justify-end p-4 sm:p-6"
        style={{ background: overlayGradient }}
      >
        <span className="font-barlow-condensed text-base font-bold text-white sm:text-[22px]">
          {display}
        </span>
        {count !== undefined && (
          <span
            data-testid="tile-count"
            className="font-dm-mono text-[11px] text-white/70 sm:text-xs"
          >
            {count.toLocaleString()} cards
          </span>
        )}
      </div>
    </Link>
  )
}

import Link from "next/link"
import { cn } from "@/lib/utils"

interface TrendingCard {
  id: string
  name: string
  set: string
  price: number
  imageUrl?: string
}

interface TrendingStripProps {
  cards?: TrendingCard[]
}

function CardPlaceholder() {
  return (
    <div className="flex h-full w-full flex-col items-center justify-center gap-2 bg-gradient-to-br from-bg-surface-2 to-bg-surface-3">
      <svg
        className="h-10 w-10 text-tertiary opacity-40"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.5"
      >
        <rect x="3" y="3" width="18" height="18" rx="2" />
        <circle cx="8.5" cy="8.5" r="1.5" />
        <path d="m21 15-5-5L5 21" />
      </svg>
    </div>
  )
}

export function TrendingStrip({ cards }: TrendingStripProps) {
  if (!cards || cards.length === 0) return null

  return (
    <section aria-label="Trending cards" className="py-8 sm:py-12">
      <p className="mb-6 px-5 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow sm:px-12">
        Trending Now
      </p>
      <div
        className={cn(
          "flex gap-4 overflow-x-auto px-5 pb-4 sm:gap-5 sm:px-12",
          "scrollbar-thin scrollbar-track-transparent scrollbar-thumb-bg-surface-3"
        )}
      >
        {cards.map((card) => (
          <Link
            key={card.id}
            href={`/cards/${card.id}`}
            className="group flex-shrink-0 transition-transform duration-150 [@media(pointer:fine)]:hover:-translate-y-1"
            style={{ width: 180 }}
          >
            <div className="mb-2.5 overflow-hidden rounded-xl border border-border bg-bg-surface-2" style={{ aspectRatio: "5/7" }}>
              {card.imageUrl ? (
                <img
                  src={card.imageUrl}
                  alt={card.name}
                  className="h-full w-full object-contain"
                />
              ) : (
                <CardPlaceholder />
              )}
            </div>
            <p className="truncate font-barlow text-[13px] font-semibold text-primary">
              {card.name}
            </p>
            <p className="truncate text-xs text-tertiary">{card.set}</p>
            <p className="font-dm-mono text-sm font-medium text-positive">
              ${card.price.toFixed(2)}
            </p>
          </Link>
        ))}
      </div>
    </section>
  )
}

