import { render, screen, fireEvent } from "@testing-library/react"
import React from "react"

vi.mock("next/link", () => ({
  default: ({ children, href, onClick, ...props }: any) =>
    React.createElement("a", { href, onClick, ...props }, children),
}))

import { GameTile } from "../GameTile"

const defaultProps = {
  code: "POKEMON",
  display: "Pok\u00e9mon",
  image: "/images/card-backs/Back_of_pokemon_card.webp",
  bgGradient: "linear-gradient(135deg, #1a1a08 0%, #3d3000 100%)",
  overlayGradient:
    "linear-gradient(180deg, rgba(252,211,77,0.08) 0%, rgba(252,211,77,0.50) 100%)",
}

const cookieSetter = vi.fn()

beforeAll(() => {
  Object.defineProperty(document, "cookie", {
    set: cookieSetter,
    get: () => "",
    configurable: true,
  })
})

beforeEach(() => {
  vi.clearAllMocks()
})

describe("GameTile", () => {
  it("renders game name", () => {
    render(<GameTile {...defaultProps} />)
    expect(screen.getByText("Pok\u00e9mon")).toBeInTheDocument()
  })

  it("renders card count when provided", () => {
    render(<GameTile {...defaultProps} count={214850} />)
    expect(screen.getByText(/214,850/)).toBeInTheDocument()
  })

  it("does not render count element when count is undefined", () => {
    render(<GameTile {...defaultProps} />)
    expect(screen.queryByTestId("tile-count")).not.toBeInTheDocument()
  })

  it("sets aria-label with count when count is provided", () => {
    render(<GameTile {...defaultProps} count={214850} />)
    const tile = screen.getByRole("link")
    expect(tile).toHaveAttribute(
      "aria-label",
      "Pok\u00e9mon \u2014 214,850 cards"
    )
  })

  it("sets aria-label without count when count is absent", () => {
    render(<GameTile {...defaultProps} />)
    const tile = screen.getByRole("link")
    expect(tile).toHaveAttribute("aria-label", "Pok\u00e9mon")
  })

  it("onClick writes sd_game_pref cookie and links to correct URL", () => {
    render(<GameTile {...defaultProps} />)
    const link = screen.getByRole("link")

    expect(link).toHaveAttribute("href", "/cards?game=POKEMON")

    fireEvent.click(link)

    expect(cookieSetter).toHaveBeenCalledWith(
      expect.stringContaining("sd_game_pref=POKEMON")
    )
    expect(cookieSetter).toHaveBeenCalledWith(
      expect.stringContaining("max-age=2592000")
    )
    expect(cookieSetter).toHaveBeenCalledWith(
      expect.stringContaining("SameSite=Lax")
    )
  })

  it("renders '0 cards' when count is 0", () => {
    render(<GameTile {...defaultProps} count={0} />)
    expect(screen.getByTestId("tile-count")).toBeInTheDocument()
    expect(screen.getByTestId("tile-count")).toHaveTextContent("0 cards")
  })

  it("sets aria-label with '0 cards' when count is 0", () => {
    render(<GameTile {...defaultProps} count={0} />)
    expect(screen.getByRole("link")).toHaveAttribute(
      "aria-label",
      "Pok\u00e9mon \u2014 0 cards"
    )
  })

  it("uses 16/10 aspect ratio", () => {
    render(<GameTile {...defaultProps} />)
    const tile = screen.getByRole("link")
    expect(tile.style.aspectRatio).toBe("16 / 10")
  })
})
